@torch.no_grad()
def get_task_embs(
    ds_descs,
    emb_model,
    emb_tokenizer,
    task_desc_format_fn,
    pooling_fn,
    device,
):
    out = dict()
    for i, (ds_name, descs) in enumerate(ds_descs.items()):
