# xdist grouping: torch tests must run on the same worker to avoid the
# triton library double-registration crash in pytest-xdist.
# ---------------------------------------------------------------------------
_TORCH_TEST_FILENAMES = {
    "test_hypernetwork",
    "test_merging",
    "test_sakana",
    "test_d2l_config",
    "test_d2l_train",
    "test_d2l_weight_transfer",
    "test_d2l_probe",
    "test_d2l_prep",
